"use strict";parserFactory.register("ruvers.ru",()=>new RuversParser);class RuversParser extends Parser{constructor(){super(),this.ChacheChapterTitle=new Map}async getChapterUrls(e){let t=(await HttpClient.wrapFetch(e.baseURI)).responseXML.querySelector("books-chapters-list"),r=new RegExp('book-id="[0-9]+"'),n=t.outerHTML.match(r)?.[0].slice(9,-1);return(await HttpClient.fetchJson("https://ruvers.ru/api/books/"+n+"/chapters/all")).json.data.map(e=>({sourceUrl:"https://ruvers.ru/"+e.book_slug+"/"+e.id,title:e.full_name,isIncludeable:1==e.is_free}))}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector("h1")?.textContent??null}findCoverImageUrl(e){return e.querySelector(".book_inner img")?.src??null}extractDescription(e){return e.querySelector("div.book_description").textContent.trim()}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.book_inner, div.book_description, div.book_information")]}fixUnicodeString(e){return e.replace(/\\u([\da-fA-F]{4})/g,(e,t)=>String.fromCharCode(parseInt(t,16)))}async fetchChapter(e){0==this.ChacheChapterTitle.size&&[...this.state.webPages.values()].filter(e=>e.isIncludeable).map(e=>this.ChacheChapterTitle.set(e.sourceUrl,e.title));let t=(await HttpClient.wrapFetch(e)).responseXML.querySelector("books-chapters-text-component"),r=new RegExp('text=".*?"'),n=t.outerHTML.match(r)?.[0].slice(12,-7);return n=n.replaceAll("\\/","/"),n=this.fixUnicodeString(n),this.buildChapter(n,e)}buildChapter(e,t){let r=Parser.makeEmptyDocForContent(t),n=r.dom.createElement("h1");n.textContent=this.ChacheChapterTitle.get(t),r.content.appendChild(n);let i=util.sanitize(e);return util.moveChildElements(i.body,r.content),r.dom}}